import { useEffect, useMemo, useState, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/router';
import {
  kundliService, db,
} from '@astro/shared';
import { doc, getDoc } from 'firebase/firestore';
import Layout from '../components/Layout';
import { useRequireAdmin } from '../lib/useAuth';

// Admin Report Activity feed - mirrors the AstroSeer admin's
// Activity tab but for the orders that flowed through OUR relay
// (channel=vercel_order). Every PDF generated by AstroSeer is
// cached on the order doc (pdfUrl + pdfBase64 + sizeBytes), so
// admin can download / view / regenerate / resend directly from
// this page without any AstroSeer round-trip on the cached path.

const STATUS_CHIP = {
  ready: 'bg-success/15 text-success border-success/40',
  paid_generating: 'bg-warning/15 text-warning border-warning/40',
  free_generating: 'bg-warning/15 text-warning border-warning/40',
  failed: 'bg-danger/15 text-danger border-danger/40',
  failed_refunded: 'bg-danger/15 text-danger border-danger/40',
  ready_rescued: 'bg-success/15 text-success border-success/40',
};
const STATUS_LABEL = {
  ready: 'SENT',
  paid_generating: 'GENERATING',
  free_generating: 'GENERATING',
  failed: 'FAILED',
  failed_refunded: 'FAILED',
  ready_rescued: 'SENT',
};

const KIND_LABEL = {
  free: 'basic',
  forecast12: 'yearly',
  careerFinance: 'career',
  lifetime: 'full_life',
};
const KIND_FULL_LABEL = {
  free: 'Free Vedic Kundli',
  forecast12: '12-Month Forecast',
  careerFinance: 'Career & Finance Deep Dive',
  lifetime: 'Lifetime Vedic Report',
};

// Date-range presets mirror what AstroSeer admin exposes so the
// feel is identical.
const DATE_PRESETS = [
  ['all', 'All time'],
  ['today', 'Today'],
  ['24h', 'Last 24h'],
  ['7d', 'Last 7d'],
  ['30d', 'Last 30d'],
  ['year', 'This year'],
];

function fmtDateTime(ts) {
  try {
    const ms = ts && ts.toMillis ? ts.toMillis()
      : ts && ts.seconds ? ts.seconds * 1000 : Number(ts) || 0;
    if (!ms) return '-';
    return new Date(ms).toLocaleString('en-GB', {
      day: '2-digit', month: 'short',
      hour: '2-digit', minute: '2-digit', second: '2-digit',
    });
  } catch (_) { return '-'; }
}
function fmtSize(bytes) {
  const n = Number(bytes || 0);
  if (!n) return '-';
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / (1024 * 1024)).toFixed(2)} MB`;
}
function fmtDurationS(start, end) {
  const ms1 = start && start.toMillis ? start.toMillis()
    : (start && start.seconds ? start.seconds * 1000 : 0);
  const ms2 = end && end.toMillis ? end.toMillis()
    : (end && end.seconds ? end.seconds * 1000 : 0);
  if (!ms1 || !ms2 || ms2 < ms1) return '-';
  return `${((ms2 - ms1) / 1000).toFixed(1)}s`;
}
function tsMillis(ts) {
  return ts && ts.toMillis ? ts.toMillis()
    : (ts && ts.seconds ? ts.seconds * 1000 : 0);
}

export default function AdminReportActivity() {
  const { loading } = useRequireAdmin();
  const router = useRouter();
  const [rows, setRows] = useState(null);
  const [usersById, setUsersById] = useState({});
  const [status, setStatus] = useState('all');
  const [datePreset, setDatePreset] = useState('all');
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [search, setSearch] = useState('');
  const [busyRow, setBusyRow] = useState('');
  const [viewer, setViewer] = useState(null);
  const [msg, setMsg] = useState('');

  const load = useCallback(async () => {
    const list = await kundliService.listAllOrdersAdmin();
    setRows(list);
    const uniq = [...new Set(list.map((o) => o.userId).filter(Boolean))];
    const missing = uniq.filter((uid) => !usersById[uid]);
    if (missing.length) {
      const fetched = { ...usersById };
      await Promise.all(missing.map(async (uid) => {
        try {
          const s = await getDoc(doc(db, 'users', uid));
          if (s.exists()) fetched[uid] = { id: s.id, ...s.data() };
        } catch (_) { /* */ }
      }));
      setUsersById(fetched);
    }
  }, [usersById]);

  useEffect(() => { load(); }, []);   // eslint-disable-line

  useEffect(() => {
    if (!autoRefresh) return undefined;
    const t = setInterval(load, 3000);
    return () => clearInterval(t);
  }, [autoRefresh, load]);

  // Server-side sweep: hits the relay's action:'sweepPending'
  // which iterates over every *_generating order and pulls fresh
  // AstroSeer status. Runs ONCE on page mount + every 30s while
  // the admin is here. So opening Report Activity == syncing
  // every pending order. The relay handles PDF fetch + email +
  // refund automatically; we just need to nudge it.
  const [sweepBusy, setSweepBusy] = useState(false);
  const [sweepInfo, setSweepInfo] = useState('');
  const sweep = useCallback(async (silent) => {
    if (!silent) setSweepBusy(true);
    try {
      const url = (typeof process !== 'undefined'
        && process.env && process.env.NEXT_PUBLIC_PUSH_ENDPOINT)
        ? process.env.NEXT_PUBLIC_PUSH_ENDPOINT
          .replace(/\/sendPush\/?$/, '/kundli')
        : 'https://astro-platform-push-relay.vercel.app/api/kundli';
      const r = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'sweepPending' }),
      });
      const j = await r.json().catch(() => ({}));
      const checked = Number(j.checked || 0);
      const ready = Number(j.ready || 0);
      const failed = Number(j.failed || 0);
      const still = Number(j.stillGenerating || 0);
      if (checked > 0) {
        setSweepInfo(`Synced ${checked} pending: `
          + `${ready} ready, ${failed} failed, ${still} still generating.`);
        // Refresh the Firestore-side rows so the UI reflects the
        // status flips the sweep just wrote.
        load();
      } else if (!silent) {
        setSweepInfo('No pending orders to sync.');
      }
      // Auto-clear the info banner after 6 seconds.
      setTimeout(() => setSweepInfo(''), 6000);
    } catch (e) {
      if (!silent) {
        setSweepInfo(`Sweep failed: ${(e && e.message) || e}`);
      }
    } finally { setSweepBusy(false); }
  }, [load]);

  // Auto-sweep: once on mount + every 30s while the page is open.
  useEffect(() => {
    sweep(true);                          // silent first-tick
    const t = setInterval(() => sweep(true), 30000);
    return () => clearInterval(t);
  }, [sweep]);

  const filtered = useMemo(() => {
    if (!Array.isArray(rows)) return null;
    const now = Date.now();
    const cutoff = (() => {
      if (datePreset === 'today') {
        const d = new Date(); d.setHours(0, 0, 0, 0); return d.getTime();
      }
      if (datePreset === '24h') return now - 24 * 3600 * 1000;
      if (datePreset === '7d') return now - 7 * 24 * 3600 * 1000;
      if (datePreset === '30d') return now - 30 * 24 * 3600 * 1000;
      if (datePreset === 'year') {
        const d = new Date(); d.setMonth(0, 1); d.setHours(0, 0, 0, 0);
        return d.getTime();
      }
      return 0;
    })();
    const q = search.trim().toLowerCase();
    return rows.filter((o) => {
      if (status === 'generating') {
        if (o.status !== 'paid_generating'
          && o.status !== 'free_generating') return false;
      } else if (status === 'sent') {
        if (o.status !== 'ready' && o.status !== 'ready_rescued') {
          return false;
        }
      } else if (status === 'failed') {
        if (o.status !== 'failed' && o.status !== 'failed_refunded') {
          return false;
        }
      }
      if (cutoff > 0) {
        const ms = tsMillis(o.paidAt);
        if (!ms || ms < cutoff) return false;
      }
      if (q) {
        const u = usersById[o.userId] || {};
        const hay = [o.id, o.userId, u.name, u.email, o.profileName,
          o.profileDob, KIND_FULL_LABEL[o.kind]]
          .join(' ').toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
  }, [rows, status, datePreset, search, usersById]);

  const totals = useMemo(() => {
    if (!Array.isArray(rows)) {
      return { generating: 0, generated: 0, sent: 0, failed: 0,
        last24h: 0, last7d: 0, all: 0 };
    }
    const now = Date.now();
    const t = { generating: 0, generated: 0, sent: 0, failed: 0,
      last24h: 0, last7d: 0, all: rows.length };
    rows.forEach((o) => {
      const ms = tsMillis(o.paidAt);
      if (o.status === 'paid_generating'
        || o.status === 'free_generating') t.generating += 1;
      else if (o.status === 'ready'
        || o.status === 'ready_rescued') {
        t.generated += 1; t.sent += 1;
      } else if (o.status === 'failed'
        || o.status === 'failed_refunded') t.failed += 1;
      if (ms && now - ms < 24 * 3600 * 1000) t.last24h += 1;
      if (ms && now - ms < 7 * 24 * 3600 * 1000) t.last7d += 1;
    });
    return t;
  }, [rows]);

  function realUrl(o) {
    if (!o) return '';
    if (o.pdfBase64) return `data:application/pdf;base64,${o.pdfBase64}`;
    return o.pdfUrl && o.pdfUrl !== 'inline' ? o.pdfUrl : '';
  }
  function downloadRow(o) {
    const url = realUrl(o);
    if (!url) { setMsg('PDF not yet cached on this order.'); return; }
    kundliService.downloadPdfFromUrl(url,
      o.pdfName || `AstroSeer-${KIND_LABEL[o.kind] || 'kundli'}.pdf`);
  }
  function viewRow(o) {
    const url = realUrl(o);
    if (!url) { setMsg('PDF not yet cached on this order.'); return; }
    setViewer({ url, name: o.pdfName
      || `AstroSeer-${KIND_LABEL[o.kind] || 'kundli'}.pdf` });
  }
  async function regenRow(o) {
    if (!o || !o.userId || !o.kundliProfileId) return;
    setBusyRow(o.id);
    setMsg('');
    try {
      const res = await kundliService.requestReport({
        uid: o.userId, kundliProfileId: o.kundliProfileId,
        kind: o.kind || 'free', regenerate: true,
      });
      if (res && res.orderId) {
        setMsg(`Regenerating... new order ${res.orderId.slice(0, 8)}.`);
        setTimeout(load, 1500);
      } else {
        setMsg('Regenerate request returned no order id.');
      }
    } catch (e) {
      setMsg((e && e.message) || 'Regenerate failed.');
    } finally { setBusyRow(''); }
  }

  if (loading) {
    return <Layout><div className="card">Loading…</div></Layout>;
  }

  return (
    <Layout>
      {/* Header */}
      <div className="flex items-baseline justify-between gap-2">
        <h1 className="text-2xl font-bold">Report Activity</h1>
        <div className="flex items-center gap-2">
          <button type="button" onClick={() => sweep(false)}
            disabled={sweepBusy}
            className="rounded-full border border-accent bg-white
              px-3 py-1 text-[11px] font-bold text-accent
              disabled:opacity-50">
            {sweepBusy ? 'Syncing...' : 'Sync pending now'}
          </button>
          <Link href="/admin-orders"
            className="text-xs font-bold text-primary
              hover:underline">
            ← Back to Orders
          </Link>
        </div>
      </div>
      <p className="mt-1 text-xs text-sub-text">
        Live feed of every kundli PDF generated through our relay.
        Auto-refreshes every 3 seconds. Times in your local timezone.
        Pending orders are server-synced every 30 seconds against
        the AstroSeer status endpoint; click <b>Sync pending now</b>
        to force an immediate check.
      </p>
      {sweepInfo && (
        <div className="mt-2 rounded-card bg-primary/10 px-3 py-2
          text-xs text-primary">
          {sweepInfo}
        </div>
      )}

      {/* Stat tiles */}
      <div className="mt-4 grid grid-cols-3 gap-2 sm:grid-cols-7">
        <Stat label="GENERATING" value={totals.generating}
          tone={totals.generating > 0 ? 'warn' : ''} />
        <Stat label="GENERATED" value={totals.generated} />
        <Stat label="SENT" value={totals.sent} tone="ok" />
        <Stat label="FAILED" value={totals.failed}
          tone={totals.failed > 0 ? 'danger' : ''} />
        <Stat label="LAST 24H" value={totals.last24h} />
        <Stat label="LAST 7D" value={totals.last7d} />
        <Stat label="ALL TIME" value={totals.all} />
      </div>

      {/* Filters */}
      <div className="surface mt-4 p-3 text-xs">
        <div className="mb-2 flex flex-wrap items-center gap-3">
          <span className="font-bold uppercase tracking-wide
            text-sub-text">Date range</span>
          {DATE_PRESETS.map(([k, label]) => (
            <button key={k} type="button"
              onClick={() => setDatePreset(k)}
              className={`rounded-full px-3 py-1 text-[11px]
                font-bold ${datePreset === k
                  ? 'bg-primary text-white'
                  : 'border border-gray-200 bg-white text-sub-text'}`}>
              {label}
            </button>
          ))}
        </div>
        <div className="mb-2 flex flex-wrap items-center gap-3">
          <span className="font-bold uppercase tracking-wide
            text-sub-text">Status</span>
          {['all', 'generating', 'sent', 'failed'].map((k) => (
            <button key={k} type="button" onClick={() => setStatus(k)}
              className={`rounded-full px-3 py-1 text-[11px]
                font-bold uppercase ${status === k
                  ? 'bg-primary text-white'
                  : 'border border-gray-200 bg-white text-sub-text'}`}>
              {k}
            </button>
          ))}
          <label className="ml-auto inline-flex items-center gap-2
            text-[11px] font-bold uppercase tracking-wide
            text-sub-text">
            <input type="checkbox" checked={autoRefresh}
              onChange={(e) => setAutoRefresh(e.target.checked)} />
            Auto-refresh
          </label>
        </div>
        <input type="text" value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search by name, email, order id, profile, kind..."
          className="w-full rounded-card border border-gray-200
            px-3 py-2 text-sm" />
      </div>

      {msg && (
        <div className="mt-3 rounded-card bg-primary/10 px-3 py-2
          text-xs text-primary">{msg}</div>
      )}

      {/* Table */}
      <div className="surface mt-4 overflow-x-auto p-0">
        <table className="w-full min-w-[1000px] text-[11px]">
          <thead className="bg-bg-light uppercase
            tracking-wide text-sub-text">
            <tr>
              <th className="px-3 py-2 text-left">Started</th>
              <th className="px-3 py-2 text-left">Report</th>
              <th className="px-3 py-2 text-left">Native</th>
              <th className="px-3 py-2 text-left">Customer</th>
              <th className="px-3 py-2 text-left">Channel</th>
              <th className="px-3 py-2 text-left">Status</th>
              <th className="px-3 py-2 text-left">Progress</th>
              <th className="px-3 py-2 text-left">Size</th>
              <th className="px-3 py-2 text-left">Generated</th>
              <th className="px-3 py-2 text-left">Sent</th>
              <th className="px-3 py-2 text-left">Order ID</th>
              <th className="px-3 py-2 text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {!filtered && (
              <tr><td colSpan="12"
                className="px-3 py-6 text-center text-sub-text">
                Loading orders…
              </td></tr>
            )}
            {filtered && filtered.length === 0 && (
              <tr><td colSpan="12"
                className="px-3 py-6 text-center text-sub-text">
                No rows match the current filters.
              </td></tr>
            )}
            {filtered && filtered.map((o) => {
              const u = usersById[o.userId] || {};
              const isReady = o.status === 'ready'
                || o.status === 'ready_rescued';
              const isGen = o.status === 'paid_generating'
                || o.status === 'free_generating';
              const url = realUrl(o);
              return (
                <tr key={o.id}
                  className="border-t border-gray-100
                    hover:bg-bg-light/40">
                  <td className="px-3 py-2 whitespace-nowrap">
                    {fmtDateTime(o.paidAt)}
                  </td>
                  <td className="px-3 py-2">
                    <span className="font-mono text-warning">
                      {KIND_LABEL[o.kind] || o.kind || '-'}
                    </span>
                  </td>
                  <td className="px-3 py-2">
                    <div className="font-semibold text-dark-text">
                      {o.profileName || '-'}
                    </div>
                    <div className="text-[10px] text-sub-text">
                      {o.profileDob}
                      {o.profileTob ? ` ${o.profileTob}` : ''}
                      {o.profileAmpm ? ` ${o.profileAmpm}` : ''}
                    </div>
                  </td>
                  <td className="px-3 py-2">
                    <Link href={`/admin-user-profile/${o.userId}`}
                      className="font-semibold text-primary
                        hover:underline">
                      {u.name || u.email || u.userCode || '(unknown)'}
                    </Link>
                    {u.email && (
                      <div className="text-[10px] text-sub-text">
                        {u.email}
                      </div>
                    )}
                  </td>
                  <td className="px-3 py-2 font-mono uppercase
                    tracking-wide text-sub-text">
                    vercel_order
                  </td>
                  <td className="px-3 py-2">
                    <span className={`inline-block rounded-full
                      border px-2 py-0.5 text-[10px] font-bold
                      uppercase tracking-wide ${STATUS_CHIP[o.status]
                        || 'bg-gray-100 text-sub-text'}`}>
                      {o.kickoffPending && isGen ? 'QUEUED'
                        : (STATUS_LABEL[o.status] || o.status || '-')}
                    </span>
                    {o.astroseerRetryCount > 0 && (
                      <div className="text-[10px] text-warning">
                        retry × {o.astroseerRetryCount}
                      </div>
                    )}
                    {o.kickoffPending && (
                      <div className="text-[10px] text-warning"
                        title={o.kickoffLastError || ''}>
                        kickoff pending
                      </div>
                    )}
                    {o.kickoffLastError && !o.kickoffPending && (
                      <div className="mt-1 line-clamp-2 max-w-[200px]
                        text-[9px] text-danger"
                        title={o.kickoffLastError}>
                        {String(o.kickoffLastError).slice(0, 60)}
                      </div>
                    )}
                  </td>
                  <td className="px-3 py-2 text-success">
                    {isReady
                      ? fmtDurationS(o.paidAt, o.deliveredAt)
                      : isGen ? '...' : '-'}
                  </td>
                  <td className="px-3 py-2">{fmtSize(o.sizeBytes)}</td>
                  <td className="px-3 py-2 whitespace-nowrap
                    text-sub-text">
                    {isReady ? fmtDateTime(o.deliveredAt) : '-'}
                  </td>
                  <td className="px-3 py-2 whitespace-nowrap
                    text-sub-text">
                    {isReady ? fmtDateTime(o.deliveredAt) : '-'}
                  </td>
                  <td className="px-3 py-2 font-mono text-[10px]
                    text-sub-text">
                    {/* 8-digit numeric ids (mintOrderId path)
                        render in full; long auto-generated ids
                        are truncated to the first 10 chars to
                        keep the column narrow. */}
                    {o.id
                      ? (/^\d{8}$/.test(o.id) ? o.id : o.id.slice(0, 10))
                      : '-'}
                  </td>
                  <td className="px-3 py-2 text-right">
                    <div className="inline-flex flex-wrap gap-1">
                      {isReady && url && (
                        <>
                          <button type="button" onClick={() => viewRow(o)}
                            className="rounded-full bg-bg-light px-2
                              py-1 text-[10px] font-bold text-primary">
                            View
                          </button>
                          <button type="button"
                            onClick={() => downloadRow(o)}
                            className="rounded-full bg-primary px-2
                              py-1 text-[10px] font-bold text-white">
                            Download
                          </button>
                        </>
                      )}
                      <button type="button" disabled={busyRow === o.id}
                        onClick={() => regenRow(o)}
                        className="rounded-full border border-accent
                          bg-white px-2 py-1 text-[10px] font-bold
                          text-accent disabled:opacity-50">
                        {busyRow === o.id ? 'Regen...' : 'Regen'}
                      </button>
                      <Link href={`/admin-user-profile/${o.userId}`}
                        className="rounded-full border border-gray-200
                          bg-white px-2 py-1 text-[10px] font-bold
                          text-sub-text">
                        Profile
                      </Link>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {filtered && (
        <p className="mt-2 text-[10px] text-sub-text">
          Showing {filtered.length} of {(rows && rows.length) || 0} rows
        </p>
      )}

      {viewer && (
        <ReportPdfViewer url={viewer.url} name={viewer.name}
          onClose={() => setViewer(null)} />
      )}
    </Layout>
  );
}

function Stat({ label, value, tone }) {
  const border = tone === 'danger' ? 'border-danger/40'
    : tone === 'warn' ? 'border-warning/40'
      : tone === 'ok' ? 'border-success/40'
        : 'border-gray-200';
  const text = tone === 'danger' ? 'text-danger'
    : tone === 'warn' ? 'text-warning'
      : tone === 'ok' ? 'text-success'
        : 'text-dark-text';
  return (
    <div className={`surface border p-3 ${border}`}>
      <div className="text-[10px] font-bold uppercase tracking-wide
        text-sub-text">{label}</div>
      <div className={`mt-0.5 text-2xl font-bold ${text}`}>
        {value}
      </div>
    </div>
  );
}

// Full-screen PDF viewer with close + download + open-in-browser.
// Identical to the one in admin-user-profile + client kundli to
// keep the experience consistent.
function ReportPdfViewer({ url, name, onClose }) {
  function download() {
    kundliService.downloadPdfFromUrl(url, name
      || 'AstroSeer-Kundli.pdf');
  }
  function openExternal() {
    try { window.open(url, '_blank'); } catch (_) { /* */ }
  }
  return (
    <div className="fixed inset-0 z-[2147483647] flex flex-col
      bg-black/80">
      <div className="flex items-center justify-between gap-2
        bg-primary px-3 py-2 text-white">
        <div className="min-w-0 flex-1 truncate text-sm font-bold">
          {name || 'Kundli PDF'}
        </div>
        <button type="button" onClick={download}
          className="rounded-full bg-white/20 px-3 py-1 text-[11px]
            font-bold hover:bg-white/30">
          Download
        </button>
        <button type="button" onClick={openExternal}
          className="rounded-full bg-white/20 px-3 py-1 text-[11px]
            font-bold hover:bg-white/30">
          Open in browser
        </button>
        <button type="button" onClick={onClose} aria-label="Close"
          className="ml-1 grid h-8 w-8 place-items-center rounded-full
            bg-white/20 text-base font-bold hover:bg-white/30">
          ×
        </button>
      </div>
      <div className="flex-1 bg-white">
        <iframe src={url} title={name || 'Kundli PDF'}
          className="h-full w-full border-0"
          style={{ minHeight: '60vh' }} />
      </div>
    </div>
  );
}
